#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; char use_numbers[4], use_special[4];
        scanf("%d %3s %3s", &N, use_numbers, use_special);
        char password[105];
        int idx=0;
        int first_len = N-2;
        for(int i=0;i<first_len;i++){
            password[idx++] = 'a' + (i % 26);
        }
        password[idx++] = (strcmp(use_numbers,"Yes")==0) ? '0' : 'a';
        password[idx++] = (strcmp(use_special,"Yes")==0) ? '!' : 'a';
        password[idx] = '\0';
        printf("%s\n", password);
    }
    return 0;
}

