code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for(int tc=0; tc<T; tc++){
            StringTokenizer st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            String useNumbers = st.nextToken();
            String useSpecial = st.nextToken();
            StringBuilder pwd = new StringBuilder();
            int firstLen = N-2;
            for(int i=0;i<firstLen;i++) pwd.append((char)('a' + (i%26)));
            pwd.append(useNumbers.equals("Yes") ? '0' : 'a');
            pwd.append(useSpecial.equals("Yes") ? '!' : 'a');
            out.append(pwd).append('\n');
        }
        System.out.print(out.toString());
    }
}

