if (input.length === 0) process.exit(0);
const T = parseInt(input[idx++], 10);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = parseInt(input[idx++], 10);
  const useNumbers = input[idx++];
  const useSpecial = input[idx++];
  const firstLen = N - 2;
