    pwd += String.fromCharCode('a'.charCodeAt(0) + (i % 26));
  }
  pwd += (useNumbers === 'Yes') ? '0' : 'a';
  pwd += (useSpecial === 'Yes') ? '!' : 'a';
  outputs.push(pwd);
}
